export default function HSNMaster() {
  const [showNew,     setShowNew]     = useState(false)
  const [search,      setSearch]      = useState('')
  const [typeFilter,  setTypeFilter]  = useState('All')
  const [form,        setForm]        = useState({})
  const [rows,        setRows]        = useState(ALL_HSN_SAC)

  const filtered = rows.filter(r =>
    (typeFilter === 'All' || r.type === typeFilter) &&
    (r.code.toLowerCase().includes(search.toLowerCase()) ||
     r.desc.toLowerCase().includes(search.toLowerCase()))
  )

  const onIgstChange = (val) => {
    const igst = parseFloat(val) || 0
    setForm(p => ({ ...p, igst: val, cgst: +(igst/2).toFixed(2), sgst: +(igst/2).toFixed(2) }))
  }

  const [editingCode, setEditingCode] = useState(null)

  const save = () => {
    if (!form.code) return toast.error('HSN/SAC Code required')
    const exists = rows.find(r => r.code === form.code)
    // Duplicate check — only when adding new (not editing same code)
    if (exists && editingCode !== form.code) {
      toast.error(`Code ${form.code} already exists! Use Edit to update.`)
      return
    }
    const newRow = {
      code: form.code, desc: form.desc || '',
      type: form.type || 'HSN',
      igst: parseFloat(form.igst) || 0,
      cgst: parseFloat(form.cgst) || 0,
      sgst: parseFloat(form.sgst) || 0,
      active: true
    }
    if (editingCode) {
      setRows(rows.map(r => r.code === editingCode ? newRow : r))
      toast.success(`HSN/SAC ${form.code} updated!`)
    } else {
      setRows([newRow, ...rows])
      toast.success(`HSN/SAC ${form.code} added!`)
    }
    setShowNew(false); setForm({}); setEditingCode(null)
  }

  const inp = { padding:'7px 10px', border:'1px solid var(--odoo-border)',
    borderRadius:5, fontSize:12, outline:'none', width:'100%' }

  return (
    <div>
      <div className="fi-lv-hdr">
        <div className="fi-lv-title">HSN / SAC Code Master <small>SAP: VK11</small></div>
        <div className="fi-lv-actions">
          <button className="btn btn-s sd-bsm">Export</button>
          <button className="btn btn-p" onClick={() => { setShowNew(true); setForm({}); setEditingCode(null) }}>+ New</button>
        </div>
      </div>

      <div style={{ padding:'8px 12px', background:'#E6F7F7', border:'1px solid #00A09D',
        borderRadius:6, marginBottom:14, fontSize:12, color:'#005A58' }}>
        <strong>HSN / SAC Code Master</strong> — GST tax classification codes for goods and services
      </div>

      {showNew && (
        <div style={{ background:'#fff', border:'1px solid var(--odoo-purple)',
          borderRadius:8, marginBottom:16, overflow:'hidden' }}>
          <div style={{ padding:'10px 16px', background:'var(--odoo-purple)',
            display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <span style={{ color:'#fff', fontWeight:700, fontSize:13 }}>{editingCode ? `Edit — ${editingCode}` : 'New HSN/SAC Code'}</span>
            <button onClick={() => { setShowNew(false); setEditingCode(null) }}
              style={{ background:'none', border:'none', color:'#fff', cursor:'pointer', fontSize:18 }}>x</button>
          </div>
          <div style={{ padding:16, display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:'10px 16px' }}>
            <div className="sd-fg">
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>HSN/SAC Code *</label>
              <input style={{ ...inp, fontFamily:'DM Mono,monospace' }}
                value={form.code || ''} onChange={e => setForm(p => ({ ...p, code: e.target.value }))} placeholder="e.g. 320810" />
            </div>
            <div className="sd-fg">
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>Type</label>
              <select style={inp} value={form.type || 'HSN'} onChange={e => setForm(p => ({ ...p, type: e.target.value }))}>
                <option>HSN</option><option>SAC</option>
              </select>
            </div>
            <div className="sd-fg" style={{ gridColumn:'span 2' }}>
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>Description</label>
              <input style={inp} value={form.desc || ''}
                onChange={e => setForm(p => ({ ...p, desc: e.target.value }))} placeholder="e.g. Powder Paints & Coatings" />
            </div>
            <div className="sd-fg">
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>IGST %</label>
              <input style={inp} type="number" value={form.igst || ''} onChange={e => onIgstChange(e.target.value)} placeholder="18" />
            </div>
            <div className="sd-fg">
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>CGST % (auto)</label>
              <input style={{ ...inp, background:'#F8F7FA', color:'#6C757D' }} type="number" value={form.cgst || ''} readOnly placeholder="9" />
            </div>
            <div className="sd-fg">
              <label style={{ fontSize:11, fontWeight:600, color:'var(--odoo-gray)', display:'block', marginBottom:4 }}>SGST % (auto)</label>
              <input style={{ ...inp, background:'#F8F7FA', color:'#6C757D' }} type="number" value={form.sgst || ''} readOnly placeholder="9" />
            </div>
            <div style={{ gridColumn:'1 / -1', display:'flex', gap:8,
              paddingTop:8, borderTop:'1px solid var(--odoo-border)' }}>
              <button className="btn btn-p" onClick={save}>Save</button>
              <button className="btn btn-s" onClick={() => setShowNew(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ display:'flex', gap:8, marginBottom:12, alignItems:'center' }}>
        <input placeholder="Search code or description..." value={search}
          onChange={e => setSearch(e.target.value)}
          style={{ padding:'6px 12px', border:'1px solid var(--odoo-border)',
            borderRadius:6, fontSize:12, outline:'none', width:300 }} />
        <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)}
          style={{ padding:'6px 10px', border:'1px solid var(--odoo-border)',
            borderRadius:6, fontSize:12, outline:'none', cursor:'pointer' }}>
          <option>All</option>
          <option>HSN</option>
          <option>SAC</option>
        </select>
        <span style={{ fontSize:11, color:'var(--odoo-gray)', marginLeft:'auto' }}>
          {filtered.length} of {rows.length} records
        </span>
      </div>

      <div style={{
        maxHeight: 'calc(100vh - 280px)',
        overflowY: 'auto',
        overflowX: 'auto',
        border: '1px solid var(--odoo-border)',
        borderRadius: 6,
      }}>
      <table className="fi-data-table" style={{ width:'100%', borderCollapse:'collapse' }}>
        <thead style={{ position:'sticky', top:0, zIndex:10, background:'#F8F4F8' }}>
          <tr>
            <th>Code</th>
            <th>Description</th>
            <th>Type</th>
            <th>IGST</th>
            <th>CGST</th>
            <th>SGST</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {filtered.slice(0, 200).map((r, i) => (
            <tr key={r.code + i} style={{ background: i%2===0 ? '#fff' : '#FAFAFA' }}>
              <td style={{ fontFamily:'DM Mono,monospace', fontWeight:700,
                color:'var(--odoo-purple)', fontSize:12 }}>{r.code}</td>
              <td style={{ fontWeight:600, fontSize:12 }}>{r.desc || '—'}</td>
              <td>
                <span style={{ padding:'2px 8px', borderRadius:8, fontSize:10, fontWeight:600,
                  background: r.type==='SAC' ? '#D1ECF1' : '#EDE0EA',
                  color: r.type==='SAC' ? '#0C5460' : '#714B67' }}>
                  {r.type}
                </span>
              </td>
              <td style={{ fontSize:11, fontWeight:600, color: r.igst > 0 ? '#155724' : '#6C757D' }}>
                {r.igst > 0 ? r.igst + '%' : 'Nil'}
              </td>
              <td style={{ fontSize:11, color:'#6C757D' }}>{r.cgst > 0 ? r.cgst + '%' : 'Nil'}</td>
              <td style={{ fontSize:11, color:'#6C757D' }}>{r.sgst > 0 ? r.sgst + '%' : 'Nil'}</td>
              <td>
                <span style={{ padding:'2px 8px', borderRadius:8, fontSize:10, fontWeight:600,
                  background:'#D4EDDA', color:'#155724' }}>Active</span>
              </td>
              <td>
                <button onClick={() => { setForm({...r}); setEditingCode(r.code); setShowNew(true) }}
                  style={{ padding:'3px 8px', fontSize:10, fontWeight:600, borderRadius:4,
                    border:'1px solid var(--odoo-purple)', background:'var(--odoo-purple-lt)',
                    color:'var(--odoo-purple)', cursor:'pointer' }}>
                  Edit
                </button>
              </td>
            </tr>
          ))}
          {filtered.length > 200 && (
            <tr>
              <td colSpan={8} style={{ padding:'10px', textAlign:'center', fontSize:12, color:'#6C757D' }}>
                Showing 200 of {filtered.length} records — use search to filter
              </td>
            </tr>
          )}
        </tbody>
      </table>
      </div>
    </div>
  )
}